document.querySelectorAll("pre > code").forEach(e=>{const n=e.parentElement;if(n.querySelector(".copy-btn"))return;const t=document.createElement("button");t.className="copy-btn",t.textContent="Copy",t.addEventListener("click",()=>{navigator.clipboard.writeText(e.innerText),t.textContent="Copied",t.classList.add("copied"),setTimeout(()=>{t.textContent="Copy",t.classList.remove("copied")},1500)}),n.appendChild(t)})